// Register plugins once at app startup
DashKit.registerPlugins(pluginTitle, pluginText);
DashKit.setSettings({ gridLayout: { margin: [8, 8] } });

// Editable dashboard with change handler
<DashKit
  config={config}
  editMode={true}
  onChange={({ config }) => setConfig(config)}
  onItemEdit={(item) => openEditDialog(item)}
/>;

// Register with markdown support
import pluginText from '@gravity-ui/dashkit/plugins';
DashKit.registerPlugins(
  pluginText.setSettings({
    apiHandler: ({ text }) => markdownToHtml(text),
  })
);

// Register the title plugin
import pluginTitle from '@gravity-ui/dashkit/plugins';
DashKit.registerPlugins(pluginTitle);
